mapper.update:
UPDATE fill_task
status = #{status}, result_file_path = #{resultFilePath}, finished_at = #{finishedAt}, error_message = #{errorMessage}, ai_remote_task_id = #{aiRemoteTaskId}, ai_provider = #{aiProvider}, ai_model = #{aiModel}, input_tokens = #{inputTokens}, output_tokens = #{outputTokens}, total_tokens = #{totalTokens}, ai_cost = #{aiCost}, ai_cost_currency = #{aiCostCurrency}, ai_cost_estimated = #{aiCostEstimated}, ai_usage_raw = #{aiUsageRaw}, version = version + 1,
WHERE id = #{id}
AND version = #{version}

UPDATE fill_task
SET user_id = #{userId}
WHERE public_id = #{publicId}
  AND user_id IS NULL

mapper.select:
SELECT *
FROM fill_task


        AND user_id = #{userId}


        AND mode = #{mode}


        AND status = #{status}


ORDER BY created_at DESC

    LIMIT #{limit}


    OFFSET #{offset}

SELECT COUNT(*)
FROM fill_task


        AND user_id = #{userId}


        AND mode = #{mode}


        AND status = #{status}

SELECT COUNT(*)                                                AS task_count,
       COALESCE(SUM(input_tokens), 0)                         AS total_input_tokens,
       COALESCE(SUM(output_tokens), 0)                        AS total_output_tokens,
       COALESCE(SUM(total_tokens), 0)                         AS total_tokens,
       COALESCE(SUM(), 0) AS total_cost
FROM fill_task


        AND user_id = #{userId}


        AND mode = #{mode}


        AND status = #{status}

SELECT COALESCE(NULLIF(ai_provider, ''), 'unknown') AS `key`, COUNT(*) AS task_count, COALESCE(SUM(input_tokens), 0) AS input_tokens, COALESCE(SUM(output_tokens), 0) AS output_tokens, COALESCE(SUM(total_tokens), 0) AS total_tokens, COALESCE(SUM(), 0) AS total_cost, COALESCE(MAX(NULLIF(ai_cost_currency, '')), 'USD') AS total_cost_currency FROM fill_task
AND user_id = #{userId}
AND mode = #{mode}
AND status = #{status}
GROUP BY COALESCE(NULLIF(ai_provider, ''), 'unknown') ORDER BY total_tokens DESC, task_count DESC

SELECT COALESCE(NULLIF(mode, ''), 'unknown') AS `key`, COUNT(*) AS task_count, COALESCE(SUM(input_tokens), 0) AS input_tokens, COALESCE(SUM(output_tokens), 0) AS output_tokens, COALESCE(SUM(total_tokens), 0) AS total_tokens, COALESCE(SUM(), 0) AS total_cost, COALESCE(MAX(NULLIF(ai_cost_currency, '')), 'USD') AS total_cost_currency FROM fill_task
AND user_id = #{userId}
AND mode = #{mode}
AND status = #{status}
GROUP BY COALESCE(NULLIF(mode, ''), 'unknown') ORDER BY total_tokens DESC, task_count DESC

SELECT COALESCE(NULLIF(status, ''), 'unknown') AS `key`, COUNT(*) AS task_count, COALESCE(SUM(input_tokens), 0) AS input_tokens, COALESCE(SUM(output_tokens), 0) AS output_tokens, COALESCE(SUM(total_tokens), 0) AS total_tokens, COALESCE(SUM(), 0) AS total_cost, COALESCE(MAX(NULLIF(ai_cost_currency, '')), 'USD') AS total_cost_currency FROM fill_task
AND user_id = #{userId}
AND mode = #{mode}
AND status = #{status}
GROUP BY COALESCE(NULLIF(status, ''), 'unknown') ORDER BY total_tokens DESC, task_count DESC

SELECT COALESCE(NULLIF(ai_cost_currency, ''), 'USD')          AS currency,
       COUNT(*)                                               AS task_count,
       COALESCE(SUM(), 0) AS total_cost
FROM fill_task


        AND user_id = #{userId}


        AND mode = #{mode}


        AND status = #{status}


GROUP BY COALESCE(NULLIF(ai_cost_currency, ''), 'USD')
ORDER BY total_cost DESC, task_count DESC

SELECT COUNT(*)
FROM fill_task


        AND user_id = #{userId}


        AND mode = #{mode}


        AND status = #{status}

    AND (
        (input_tokens IS NULL OR input_tokens = 0)
        AND (output_tokens IS NULL OR output_tokens = 0)
        AND (total_tokens IS NULL OR total_tokens = 0)
    )
